-- Seed all 299 textbook lessons (korean-1, daily-routine, kdrama, grammar-mastery)
-- Safe to run multiple times due to ON CONFLICT DO UPDATE

ON CONFLICT (book, sort_order) DO UPDATE SET
  title_en = EXCLUDED.title_en,
  title_ko = EXCLUDED.title_ko,
  title_ar = EXCLUDED.title_ar,
  description = EXCLUDED.description,
  description_ar = EXCLUDED.description_ar,
  emoji = EXCLUDED.emoji,
  topik_level = EXCLUDED.topik_level,
  is_published = EXCLUDED.is_published;